pub const TRITON_PHASE_COUNT: usize = 3;
pub const AEON_RESOLUTION: usize = 12;
pub const HEXON_COUPLING: usize = 6;

pub const OPTIMIZER_ALIAS_REQUIRES_RESOLUTION_LIFT_THEOREM: &str =
    "Gnosis.UniversalIntelligenceSSMClosure.optimizer_alias_requires_resolution_lift";
pub const OPTIMIZER_RESIDUE_REQUIRES_RESOLUTION_LIFT_THEOREM: &str =
    "Gnosis.UniversalIntelligenceSSMClosure.optimizer_residue_requires_resolution_lift";
pub const OPTIMIZER_READY_ADMITS_RUNTIME_WORK_THEOREM: &str =
    "Gnosis.UniversalIntelligenceSSMClosure.optimizer_ready_admits_runtime_work";
pub const AEON_EIGHT_HEAD_OPTIMIZER_REQUIRES_LIFT_THEOREM: &str =
    "Gnosis.UniversalIntelligenceSSMClosure.aeon_eight_head_optimizer_requires_lift";
pub const LIFTED_EIGHT_HEAD_OPTIMIZER_ADMITS_RUNTIME_WORK_THEOREM: &str =
    "Gnosis.UniversalIntelligenceSSMClosure.lifted_eight_head_optimizer_admits_runtime_work";
pub const LIFTED_PINK_EIGHT_HEAD_OPTIMIZER_ADMITS_RUNTIME_WORK_THEOREM: &str =
    "Gnosis.UniversalIntelligenceSSMClosure.lifted_pink_eight_head_optimizer_admits_runtime_work";

pub const AEON_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE: &[&str] = &[
    AEON_EIGHT_HEAD_OPTIMIZER_REQUIRES_LIFT_THEOREM,
    OPTIMIZER_ALIAS_REQUIRES_RESOLUTION_LIFT_THEOREM,
];
pub const ALIASED_OPTIMIZER_THEOREM_LINEAGE: &[&str] =
    &[OPTIMIZER_ALIAS_REQUIRES_RESOLUTION_LIFT_THEOREM];
pub const RESIDUE_OPTIMIZER_THEOREM_LINEAGE: &[&str] =
    &[OPTIMIZER_RESIDUE_REQUIRES_RESOLUTION_LIFT_THEOREM];
pub const LIFTED_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE: &[&str] = &[
    LIFTED_EIGHT_HEAD_OPTIMIZER_ADMITS_RUNTIME_WORK_THEOREM,
    OPTIMIZER_READY_ADMITS_RUNTIME_WORK_THEOREM,
];
pub const LIFTED_PINK_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE: &[&str] = &[
    LIFTED_PINK_EIGHT_HEAD_OPTIMIZER_ADMITS_RUNTIME_WORK_THEOREM,
    OPTIMIZER_READY_ADMITS_RUNTIME_WORK_THEOREM,
];
pub const READY_OPTIMIZER_THEOREM_LINEAGE: &[&str] = &[OPTIMIZER_READY_ADMITS_RUNTIME_WORK_THEOREM];
pub const UNPROVED_THRESHOLD_POLICY_THEOREM_LINEAGE: &[&str] = &[];

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AttentionClosureKind {
    AliasedNoise,
    StructuredSignal,
    SeparatedResidue,
    AliasedClosed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ResolutionLiftAction {
    None,
    LiftResolution,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AttentionClosureState {
    pub heads: usize,
    pub coupling: usize,
    pub observer_resolution: usize,
    pub source_resolution: usize,
    pub folded_coordinate: usize,
    pub unresolved_residue: usize,
    pub head_trace: Vec<usize>,
    pub trace_separated: bool,
    pub kind: AttentionClosureKind,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ResolutionLiftDecision {
    pub action: ResolutionLiftAction,
    pub before: AttentionClosureState,
    pub after: AttentionClosureState,
    pub reason: &'static str,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AttentionClosureOptimizationPolicy {
    pub decision: ResolutionLiftDecision,
    pub preserve_heads: bool,
    pub allow_head_pruning: bool,
    pub allow_speculative_decode: bool,
    pub allow_standing_wave_compression: bool,
    pub route_action: ResolutionLiftAction,
    pub speculative_depth_limit: usize,
    pub telemetry_label: &'static str,
    pub theorem_lineage: &'static [&'static str],
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct AttentionClosureWorkload {
    pub hidden_dim: usize,
    pub batch_size: usize,
    pub layer_count: usize,
    pub standing_count: usize,
    pub requested_speculative_depth: usize,
    pub speculative_candidates: usize,
    pub head_prune_candidates: usize,
    pub head_dim: usize,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AttentionClosureWorkEstimate {
    pub baseline_optimizer_units: usize,
    pub gated_optimizer_units: usize,
    pub avoided_optimizer_units: usize,
    pub avoided_compress_decompress_units: usize,
    pub avoided_speculative_units: usize,
    pub preserved_head_prune_units: usize,
    pub full_route_bytes_when_lifted: usize,
    pub compressed_route_bytes_if_stable: usize,
}

pub fn multi_head_phase_count(heads: usize) -> usize {
    TRITON_PHASE_COUNT * heads
}

pub fn attention_head_phase(head: usize) -> usize {
    TRITON_PHASE_COUNT * (head + 1)
}

pub fn attention_head_coordinate_at_resolution(head: usize, resolution: usize) -> usize {
    attention_head_phase(head) % resolution.max(1)
}

pub fn n_head_coordinate_trace(heads: usize, resolution: usize) -> Vec<usize> {
    (0..heads)
        .map(|head| attention_head_coordinate_at_resolution(head, resolution))
        .collect()
}

pub fn trace_separated(trace: &[usize]) -> bool {
    for i in 0..trace.len() {
        for j in (i + 1)..trace.len() {
            if trace[i] == trace[j] {
                return false;
            }
        }
    }
    true
}

pub fn classify_attention_closure(
    separated: bool,
    unresolved_residue: usize,
) -> AttentionClosureKind {
    match (separated, unresolved_residue) {
        (true, 0) => AttentionClosureKind::StructuredSignal,
        (false, 0) => AttentionClosureKind::AliasedClosed,
        (true, _) => AttentionClosureKind::SeparatedResidue,
        (false, _) => AttentionClosureKind::AliasedNoise,
    }
}

pub fn attention_closure_state(
    heads: usize,
    coupling: usize,
    observer_resolution: usize,
) -> AttentionClosureState {
    let observer_resolution = observer_resolution.max(1);
    let source_resolution = multi_head_phase_count(heads) + coupling;
    let folded_coordinate = source_resolution % observer_resolution;
    let unresolved_residue = source_resolution.saturating_sub(observer_resolution);
    let head_trace = n_head_coordinate_trace(heads, observer_resolution);
    let separated = trace_separated(&head_trace);

    AttentionClosureState {
        heads,
        coupling,
        observer_resolution,
        source_resolution,
        folded_coordinate,
        unresolved_residue,
        head_trace,
        trace_separated: separated,
        kind: classify_attention_closure(separated, unresolved_residue),
    }
}

pub fn aeon_eight_head_closure_state() -> AttentionClosureState {
    attention_closure_state(8, 0, AEON_RESOLUTION)
}

pub fn lifted_eight_head_closure_state() -> AttentionClosureState {
    attention_closure_state(8, 0, multi_head_phase_count(8))
}

pub fn lifted_pink_eight_head_closure_state() -> AttentionClosureState {
    attention_closure_state(
        8,
        HEXON_COUPLING,
        multi_head_phase_count(8) + HEXON_COUPLING,
    )
}

pub fn apply_dark_deceptacon_resolution_lift(
    state: AttentionClosureState,
    residue_threshold: usize,
) -> ResolutionLiftDecision {
    let threshold = residue_threshold.max(1);
    let should_lift = !state.trace_separated || state.unresolved_residue >= threshold;
    if !should_lift {
        return ResolutionLiftDecision {
            action: ResolutionLiftAction::None,
            before: state.clone(),
            after: state,
            reason: "attention trace already separated under the current observer resolution",
        };
    }

    let after = attention_closure_state(state.heads, state.coupling, state.source_resolution);

    ResolutionLiftDecision {
        action: ResolutionLiftAction::LiftResolution,
        before: state,
        after,
        reason:
            "attention trace is aliased or leaking; lift observer resolution to the source phase",
    }
}

fn is_aeon_eight_head_alias_witness(state: &AttentionClosureState) -> bool {
    state.heads == 8
        && state.coupling == 0
        && state.observer_resolution == AEON_RESOLUTION
        && state.source_resolution == multi_head_phase_count(8)
}

fn is_lifted_eight_head_closure_witness(state: &AttentionClosureState) -> bool {
    state.heads == 8
        && state.coupling == 0
        && state.observer_resolution == multi_head_phase_count(8)
        && state.source_resolution == multi_head_phase_count(8)
        && state.trace_separated
        && state.unresolved_residue == 0
}

fn is_lifted_pink_eight_head_closure_witness(state: &AttentionClosureState) -> bool {
    state.heads == 8
        && state.coupling == HEXON_COUPLING
        && state.observer_resolution == multi_head_phase_count(8) + HEXON_COUPLING
        && state.source_resolution == multi_head_phase_count(8) + HEXON_COUPLING
        && state.trace_separated
        && state.unresolved_residue == 0
}

pub fn attention_closure_theorem_lineage(
    decision: &ResolutionLiftDecision,
) -> &'static [&'static str] {
    match decision.action {
        ResolutionLiftAction::LiftResolution => {
            if is_aeon_eight_head_alias_witness(&decision.before) {
                AEON_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE
            } else if !decision.before.trace_separated {
                ALIASED_OPTIMIZER_THEOREM_LINEAGE
            } else {
                RESIDUE_OPTIMIZER_THEOREM_LINEAGE
            }
        }
        ResolutionLiftAction::None => {
            if is_lifted_pink_eight_head_closure_witness(&decision.after) {
                LIFTED_PINK_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE
            } else if is_lifted_eight_head_closure_witness(&decision.after) {
                LIFTED_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE
            } else if decision.after.trace_separated && decision.after.unresolved_residue == 0 {
                READY_OPTIMIZER_THEOREM_LINEAGE
            } else {
                UNPROVED_THRESHOLD_POLICY_THEOREM_LINEAGE
            }
        }
    }
}

pub fn attention_closure_optimization_policy(
    state: AttentionClosureState,
    residue_threshold: usize,
    requested_speculative_depth: usize,
) -> AttentionClosureOptimizationPolicy {
    let requested_depth = requested_speculative_depth.max(1);
    let decision = apply_dark_deceptacon_resolution_lift(state, residue_threshold);
    let lift_required = decision.action == ResolutionLiftAction::LiftResolution;
    let theorem_lineage = attention_closure_theorem_lineage(&decision);

    AttentionClosureOptimizationPolicy {
        decision,
        preserve_heads: lift_required,
        allow_head_pruning: !lift_required,
        allow_speculative_decode: !lift_required,
        allow_standing_wave_compression: !lift_required,
        route_action: if lift_required {
            ResolutionLiftAction::LiftResolution
        } else {
            ResolutionLiftAction::None
        },
        speculative_depth_limit: if lift_required { 1 } else { requested_depth },
        telemetry_label: if lift_required {
            "attention_closure_lift_required"
        } else {
            "attention_closure_structured"
        },
        theorem_lineage,
    }
}

pub fn closure_adjusted_speculative_depth(
    requested_depth: usize,
    state: AttentionClosureState,
    residue_threshold: usize,
) -> usize {
    attention_closure_optimization_policy(state, residue_threshold, requested_depth)
        .speculative_depth_limit
}

pub fn estimate_closure_saved_work(
    policy: &AttentionClosureOptimizationPolicy,
    workload: AttentionClosureWorkload,
) -> AttentionClosureWorkEstimate {
    let hidden_dim = workload.hidden_dim;
    let batch_size = workload.batch_size.max(1);
    let layer_count = workload.layer_count.max(1);
    let standing_count = workload.standing_count.min(hidden_dim);
    let requested_depth = workload.requested_speculative_depth.max(1);

    let compress_decompress_units = layer_count
        .saturating_mul(batch_size)
        .saturating_mul(standing_count.saturating_add(hidden_dim));
    let speculative_units = workload
        .speculative_candidates
        .saturating_mul(requested_depth);
    let head_prune_units = workload
        .head_prune_candidates
        .saturating_mul(workload.head_dim.max(1));

    let baseline_optimizer_units = compress_decompress_units
        .saturating_add(speculative_units)
        .saturating_add(head_prune_units);

    let gated_compress_decompress_units = if policy.allow_standing_wave_compression {
        compress_decompress_units
    } else {
        0
    };
    let gated_speculative_units = if policy.allow_speculative_decode {
        workload
            .speculative_candidates
            .saturating_mul(policy.speculative_depth_limit.max(1))
    } else {
        0
    };
    let gated_head_prune_units = if policy.allow_head_pruning {
        head_prune_units
    } else {
        0
    };

    let gated_optimizer_units = gated_compress_decompress_units
        .saturating_add(gated_speculative_units)
        .saturating_add(gated_head_prune_units);

    AttentionClosureWorkEstimate {
        baseline_optimizer_units,
        gated_optimizer_units,
        avoided_optimizer_units: baseline_optimizer_units.saturating_sub(gated_optimizer_units),
        avoided_compress_decompress_units: compress_decompress_units
            .saturating_sub(gated_compress_decompress_units),
        avoided_speculative_units: speculative_units.saturating_sub(gated_speculative_units),
        preserved_head_prune_units: head_prune_units.saturating_sub(gated_head_prune_units),
        full_route_bytes_when_lifted: layer_count
            .saturating_mul(batch_size)
            .saturating_mul(hidden_dim)
            .saturating_mul(std::mem::size_of::<f32>()),
        compressed_route_bytes_if_stable: layer_count
            .saturating_mul(batch_size)
            .saturating_mul(standing_count)
            .saturating_mul(std::mem::size_of::<f32>()),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn aeon_eight_head_aliases() {
        let state = aeon_eight_head_closure_state();
        assert_eq!(state.source_resolution, 24);
        assert_eq!(state.folded_coordinate, 0);
        assert_eq!(state.unresolved_residue, 12);
        assert_eq!(state.head_trace, vec![3, 6, 9, 0, 3, 6, 9, 0]);
        assert!(!state.trace_separated);
        assert_eq!(state.kind, AttentionClosureKind::AliasedNoise);
    }

    #[test]
    fn lifted_eight_head_separates_and_closes() {
        let state = lifted_eight_head_closure_state();
        assert_eq!(state.observer_resolution, 24);
        assert_eq!(state.unresolved_residue, 0);
        assert_eq!(state.head_trace, vec![3, 6, 9, 12, 15, 18, 21, 0]);
        assert!(state.trace_separated);
        assert_eq!(state.kind, AttentionClosureKind::StructuredSignal);
    }

    #[test]
    fn lifted_pink_eight_head_separates_and_closes() {
        let state = lifted_pink_eight_head_closure_state();
        assert_eq!(state.source_resolution, 30);
        assert_eq!(state.unresolved_residue, 0);
        assert_eq!(state.head_trace, vec![3, 6, 9, 12, 15, 18, 21, 24]);
        assert!(state.trace_separated);
        assert_eq!(state.kind, AttentionClosureKind::StructuredSignal);
    }

    #[test]
    fn dark_deceptacon_lifts_aliased_trace() {
        let decision = apply_dark_deceptacon_resolution_lift(aeon_eight_head_closure_state(), 1);
        assert_eq!(decision.action, ResolutionLiftAction::LiftResolution);
        assert_eq!(decision.before.kind, AttentionClosureKind::AliasedNoise);
        assert_eq!(decision.after.kind, AttentionClosureKind::StructuredSignal);
        assert_eq!(decision.after.unresolved_residue, 0);
    }

    #[test]
    fn optimization_policy_preserves_heads_and_defers_work_when_aliased() {
        let policy = attention_closure_optimization_policy(aeon_eight_head_closure_state(), 1, 8);

        assert_eq!(policy.decision.action, ResolutionLiftAction::LiftResolution);
        assert!(policy.preserve_heads);
        assert!(!policy.allow_head_pruning);
        assert!(!policy.allow_speculative_decode);
        assert!(!policy.allow_standing_wave_compression);
        assert_eq!(policy.speculative_depth_limit, 1);
        assert_eq!(policy.telemetry_label, "attention_closure_lift_required");
        assert_eq!(
            policy.theorem_lineage,
            AEON_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE
        );
    }

    #[test]
    fn optimization_policy_allows_work_after_resolution_lift() {
        let policy = attention_closure_optimization_policy(lifted_eight_head_closure_state(), 1, 8);

        assert_eq!(policy.decision.action, ResolutionLiftAction::None);
        assert!(!policy.preserve_heads);
        assert!(policy.allow_head_pruning);
        assert!(policy.allow_speculative_decode);
        assert!(policy.allow_standing_wave_compression);
        assert_eq!(policy.speculative_depth_limit, 8);
        assert_eq!(policy.telemetry_label, "attention_closure_structured");
        assert_eq!(
            policy.theorem_lineage,
            LIFTED_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE
        );
    }

    #[test]
    fn optimization_policy_names_pink_closure_theorem_after_lift() {
        let policy =
            attention_closure_optimization_policy(lifted_pink_eight_head_closure_state(), 1, 8);

        assert_eq!(policy.decision.action, ResolutionLiftAction::None);
        assert_eq!(
            policy.theorem_lineage,
            LIFTED_PINK_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE
        );
    }

    #[test]
    fn work_estimate_counts_avoided_optimizer_work() {
        let policy = attention_closure_optimization_policy(aeon_eight_head_closure_state(), 1, 8);
        let estimate = estimate_closure_saved_work(
            &policy,
            AttentionClosureWorkload {
                hidden_dim: 5_376,
                batch_size: 2,
                layer_count: 34,
                standing_count: 1_612,
                requested_speculative_depth: 8,
                speculative_candidates: 16,
                head_prune_candidates: 8,
                head_dim: 672,
            },
        );

        assert_eq!(estimate.gated_optimizer_units, 0);
        assert!(estimate.avoided_optimizer_units > 0);
        assert!(estimate.avoided_compress_decompress_units > 0);
        assert_eq!(estimate.avoided_speculative_units, 128);
        assert_eq!(estimate.preserved_head_prune_units, 5_376);
        assert!(estimate.full_route_bytes_when_lifted > estimate.compressed_route_bytes_if_stable);
    }
}
